ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?fees ?taxes WHERE {
  ?house a :House .
  ?salerecord a :SaleRecord .
  ?salerecord p:hasHouse ?house .
  ?house p:Fees ?fees .
  ?house p:Taxes ?taxes .
  ?salerecord p:purchase_price ?purchase_price_x .
  { SELECT (MAX(?m0) AS ?m) WHERE { ?s0 p:purchase_price ?m0 } }
  FILTER(xsd:double(?purchase_price_x) = xsd:double(?m))
} }
  component: { SELECT ?fees WHERE {
  ?house a :House .
  ?salerecord a :SaleRecord .
  ?salerecord p:hasHouse ?house .
  ?house p:Fees ?fees .
  ?salerecord p:purchase_price ?purchase_price_x .
  { SELECT (MAX(?m0) AS ?m) WHERE { ?s0 p:purchase_price ?m0 } }
  FILTER(xsd:double(?purchase_price_x) = xsd:double(?m))
} }
  component_2: { SELECT ?taxes WHERE {
  ?house a :House .
  ?salerecord a :SaleRecord .
  ?salerecord p:hasHouse ?house .
  ?house p:Taxes ?taxes .
  ?salerecord p:purchase_price ?purchase_price_x .
  { SELECT (MAX(?m0) AS ?m) WHERE { ?s0 p:purchase_price ?m0 } }
  FILTER(xsd:double(?purchase_price_x) = xsd:double(?m))
} }
}

PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?taxes WHERE {
  ?house a :House .
  ?propertytype a :PropertyType .
  ?house p:hasPropertyType ?propertytype .
  ?house p:Taxes ?taxes .
  ?propertytype p:type ?type_f .
  FILTER(STR(?type_f) = STR("Condo"))
} }
  component_2: { SELECT ?fees WHERE {
  ?house a :House .
  ?propertytype a :PropertyType .
  ?house p:hasPropertyType ?propertytype .
  ?house p:Fees ?fees .
  ?propertytype p:type ?type_f .
  FILTER(STR(?type_f) = STR("Condo"))
} }
  full: { SELECT ?fees ?taxes WHERE {
  ?house a :House .
  ?propertytype a :PropertyType .
  ?house p:hasPropertyType ?propertytype .
  ?house p:Fees ?fees .
  ?house p:Taxes ?taxes .
  ?propertytype p:type ?type_f .
  FILTER(STR(?type_f) = STR("Condo"))
} }
}
